import Vue from 'vue'
import Router from 'vue-router'
import general from '@/components/general'

Vue.use(Router)

export default new Router({
  routes: [
    {
      path: '/',
      name: 'general',
      component: general,
      meta: { title: "U create the world" }
    },
    {
      path: '/',
      name: 'welcome',
      component: r => require.ensure([], () => r(require('@/components/welcome')), 'welcome')
    },
    {
      path: '/',
      name: 'photos',
      component: r => require.ensure([], () => r(require('@/components/photos')), 'photos')
    },
    {
      path: '/',
      name: 'toys',
      component: r => require.ensure([], () => r(require('@/components/toys')), 'toys')
    },
    {
      path: '/',
      name: 'homepage',
      component: r => require.ensure([], () => r(require('@/components/homepage')), 'homepage')
    },
  ]
})



